console.log('   - Processing 25 customers at once could overwhelm memory');
console.log('   - If one customer fails, we don\'t want to lose all progress');
console.log('   - We can extend the lease between batches to prevent timeout');
console.log('   - Better error handling and progress tracking');
console.log('-'.repeat(80));

return [{ json: dummyTask }];

// STEP 2: Prepare Units for Batch Processing
// This converts the task data into individual units that can be batched

const item = $input.item;
const customers = item.json.taskData.customers;
const batchSize = item.json.taskData.batchSize;

console.log('\n📦 STEP 2: PREPARE UNITS');
console.log('-'.repeat(80));
console.log('Converting', customers.length, 'customers into individual processing units...');

// Create one item per customer
const units = customers.map((customer, index) => ({
  json: {
    // Preserve original task context
    taskId: item.json.taskId,
    taskName: item.json.taskName,
    emailTemplate: item.json.taskData.emailTemplate,
    leaseExpiresAt: item.json.taskData.leaseExpiresAt,
    batchSize: batchSize,

    // Unit-specific data
    customer: customer,
    unitIndex: index,
    totalUnits: customers.length,
    unitId: `customer-${customer.id}`
  }
}));

console.log('✓ Created', units.length, 'processing units');
console.log('\nFirst 3 units:');
for (let i = 0; i < Math.min(3, units.length); i++) {
  console.log(`   Unit ${i}: ${units[i].json.customer.name} (${units[i].json.customer.email})`);
}
console.log('   ...');
console.log(`   Unit ${units.length - 1}: ${units[units.length - 1].json.customer.name}`);

console.log('\n💡 WHAT HAPPENED?');
console.log('   - Each customer is now a separate "unit" that can be processed');
console.log('   - Each unit carries the task context (taskId, lease time, etc.)');
console.log('   - Now we have', units.length, 'items flowing through the workflow');
console.log('-'.repeat(80));

return units;

// STEP 3.1: Show Batch Information
// This runs ONCE per batch (not per item in batch)

const items = $input.all();
const splitNode = $('STEP 3: Split Into Batches');

// Get batch information from the splitInBatches node context
const currentBatch = (splitNode.context.batchIndex || 0) + 1;
const totalBatches = Math.ceil(items[0].json.totalUnits / items[0].json.batchSize);
const isLastBatch = splitNode.context.noItemsLeft || false;

console.log('\n' + '█'.repeat(80));
console.log(`📊 BATCH ${currentBatch} of ${totalBatches}`);
console.log('█'.repeat(80));
console.log('Batch contains', items.length, 'customers:');

items.forEach((item, idx) => {
  console.log(`   ${idx + 1}. ${item.json.customer.name} (${item.json.customer.email}) - ${item.json.customer.status}`);
});

console.log('\n💡 BATCH CONTEXT:');
console.log('   - This batch will be processed as a group');
console.log('   - All', items.length, 'items move together to the next node');
console.log('   - After processing, we\'ll loop back for the next batch');
console.log('   - Last batch?', isLastBatch ? 'YES ✓' : 'NO, more batches remain');
console.log('   - Split node context.noItemsLeft:', splitNode.context.noItemsLeft);
console.log('-'.repeat(80));

// Add batch metadata to each item
const enrichedItems = items.map(item => ({
  json: {
    ...item.json,
    batchNumber: currentBatch,
    totalBatches: totalBatches,
    isLastBatch: isLastBatch,
    itemsInBatch: items.length
  }
}));

return enrichedItems;

// STEP 4: Process Each Customer in the Batch
// This simulates sending emails to each customer

const items = $input.all();
const batchStartTime = Date.now();
const batchNumber = items[0].json.batchNumber;

console.log('\n⚙️  STEP 4: PROCESSING BATCH', batchNumber);
console.log('-'.repeat(80));

const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const customer = item.json.customer;
  const startTime = Date.now();

  console.log(`\n   Processing ${i + 1}/${items.length}: ${customer.name}...`);

  try {
    // Simulate email sending (50-150ms)
    const processingTime = Math.floor(Math.random() * 100) + 50;
    await new Promise(resolve => setTimeout(resolve, processingTime));

    // Skip inactive customers
    if (customer.status === 'inactive') {
      console.log(`      ⚠️  SKIPPED - Customer is inactive`);
      results.push({
        json: {
          ...item.json,
          processingResult: 'skipped',
          reason: 'inactive_customer',
          processingTimeMs: Date.now() - startTime
        }
      });
      continue;
    }

    // Simulate occasional errors (10% chance)
    if (Math.random() < 0.1) {
      throw new Error('SMTP timeout - mail server not responding');
    }

    // Success!
    console.log(`      ✓ Email sent successfully (${processingTime}ms)`);
    console.log(`         To: ${customer.email}`);
    console.log(`         Template: ${item.json.emailTemplate}`);

    results.push({
      json: {
        ...item.json,
        processingResult: 'success',
        emailSentAt: new Date().toISOString(),
        processingTimeMs: Date.now() - startTime
      }
    });

  } catch (error) {
    console.log(`      ✗ FAILED - ${error.message}`);
    results.push({
      json: {
        ...item.json,
        processingResult: 'failed',
        error: {
          message: error.message,
          timestamp: new Date().toISOString()
        },
        processingTimeMs: Date.now() - startTime
      }
    });
  }
}

const batchDuration = Date.now() - batchStartTime;
const successCount = results.filter(r => r.json.processingResult === 'success').length;
const failedCount = results.filter(r => r.json.processingResult === 'failed').length;
const skippedCount = results.filter(r => r.json.processingResult === 'skipped').length;

console.log('\n📈 BATCH', batchNumber, 'SUMMARY:');
console.log(`   ✓ Success: ${successCount}`);
console.log(`   ✗ Failed: ${failedCount}`);
console.log(`   ⚠️  Skipped: ${skippedCount}`);
console.log(`   ⏱️  Total time: ${batchDuration}ms`);
console.log('-'.repeat(80));

// Add batch summary to each result
for (const result of results) {
  result.json.batchDuration = batchDuration;
  result.json.batchSuccessCount = successCount;
  result.json.batchFailedCount = failedCount;
  result.json.batchSkippedCount = skippedCount;
}

return results;

// STEP 4.1: DUMMY NODE - Validate Results
// This is an additional step in the loop to demonstrate multi-step processing

const items = $input.all();
const batchNumber = items[0].json.batchNumber;

console.log('\n🔍 STEP 4.1: VALIDATE BATCH RESULTS');
console.log('-'.repeat(80));
console.log('Validating', items.length, 'processed items from batch', batchNumber);

// Add validation timestamp
const validatedItems = items.map(item => ({
  json: {
    ...item.json,
    validatedAt: new Date().toISOString(),
    validationPassed: item.json.processingResult !== 'failed'
  }
}));

const passedCount = validatedItems.filter(i => i.json.validationPassed).length;
const failedCount = validatedItems.length - passedCount;

console.log(`   ✓ Validation passed: ${passedCount}`);
console.log(`   ✗ Validation failed: ${failedCount}`);
console.log('\n💡 This is a DUMMY step to show additional processing in the loop');
console.log('-'.repeat(80));

return validatedItems;

// STEP 5: Check Lease and Decide if Extension Needed
// This is the "predictive" part - we check BEFORE we run out of time

const items = $input.all();
const now = Date.now();
const leaseExpiresAt = new Date(items[0].json.leaseExpiresAt).getTime();
const remainingMs = leaseExpiresAt - now;
const remainingSeconds = Math.floor(remainingMs / 1000);

// Calculate average batch processing time
const batchDuration = items[0].json.batchDuration;
const currentBatch = items[0].json.batchNumber;
const totalBatches = items[0].json.totalBatches;
const remainingBatches = totalBatches - currentBatch;

// Estimate time needed for remaining work
const estimatedRemainingTime = batchDuration * remainingBatches;
const bufferTime = 10000; // 10 second safety buffer
const timeNeeded = estimatedRemainingTime + bufferTime;

console.log('\n🔍 STEP 5: LEASE CHECK (Predictive)');
console.log('-'.repeat(80));
console.log('Current time:', new Date(now).toISOString());
console.log('Lease expires:', new Date(leaseExpiresAt).toISOString());
console.log('Remaining lease time:', remainingSeconds, 'seconds');
console.log('\n📊 PREDICTION:');
console.log('   - Last batch took:', batchDuration, 'ms');
console.log('   - Remaining batches:', remainingBatches);
console.log('   - Estimated time needed:', Math.floor(estimatedRemainingTime / 1000), 'seconds');
console.log('   - Safety buffer:', Math.floor(bufferTime / 1000), 'seconds');
console.log('   - Total time needed:', Math.floor(timeNeeded / 1000), 'seconds');

const shouldExtend = remainingMs < timeNeeded;

if (shouldExtend) {
  console.log('\n⚠️  WARNING: Lease will expire before we finish!');
  console.log('   Decision: EXTEND LEASE NOW (preventive action)');
} else {
  console.log('\n✓ OK: We have enough time to continue');
  console.log('   Decision: No extension needed');
}

console.log('\n💡 WHY THIS MATTERS:');
console.log('   - If lease expires mid-processing, another worker might grab this task');
console.log('   - That would cause duplicate processing!');
console.log('   - By checking BEFORE each batch, we stay ahead of expiration');
console.log('-'.repeat(80));

// Enrich items with lease check results
for (const item of items) {
  item.json.remainingLeaseMs = remainingMs;
  item.json.shouldExtendLease = shouldExtend;
  item.json.estimatedTimeNeeded = timeNeeded;
}

return items;

// STEP 6.1: Simulate Extending the Lease
// In production, this would call the database: heartbeat_task()

const items = $input.all();
const extendByMinutes = 5;
const extendByMs = extendByMinutes * 60 * 1000;

const oldExpiry = new Date(items[0].json.leaseExpiresAt);
const newExpiry = new Date(oldExpiry.getTime() + extendByMs);

console.log('\n🔄 STEP 6.1: EXTENDING LEASE');
console.log('-'.repeat(80));
console.log('Old expiry:', oldExpiry.toISOString());
console.log('Extending by:', extendByMinutes, 'minutes');
console.log('New expiry:', newExpiry.toISOString());
console.log('\n💡 IN PRODUCTION:');
console.log('   - This would call: SELECT heartbeat_task(taskId, \'5 minutes\')');
console.log('   - Database updates the lease_expires_at timestamp');
console.log('   - Other workers see this task is still locked to us');
console.log('-'.repeat(80));

// Update all items with new lease time
for (const item of items) {
  item.json.leaseExpiresAt = newExpiry.toISOString();
  item.json.leaseExtended = true;
  item.json.leaseExtensionCount = (item.json.leaseExtensionCount || 0) + 1;
}

return items;

// STEP 6.2: DUMMY NODE - Update Metrics
// This simulates updating worker metrics after lease extension

const items = $input.all();
const batchNumber = items[0].json.batchNumber;

console.log('\n📊 STEP 6.2: UPDATE METRICS (Dummy)');
console.log('-'.repeat(80));
console.log('Batch:', batchNumber);
console.log('Lease extensions so far:', items[0].json.leaseExtensionCount || 0);
console.log('\n💡 In production, this would update worker metrics:');
console.log('   - Increment lease extension counter');
console.log('   - Log to monitoring system');
console.log('   - Update heartbeat timestamp');
console.log('-'.repeat(80));

return items;

// STEP 7: Log Batch Completion Status
// Prepare for routing decision

const items = $input.all();
const isLastBatch = items[0].json.isLastBatch;
const currentBatch = items[0].json.batchNumber;
const totalBatches = items[0].json.totalBatches;

console.log('\n🏁 STEP 7: BATCH COMPLETION CHECK');
console.log('-'.repeat(80));
console.log('Current batch:', currentBatch, 'of', totalBatches);
console.log('Is last batch?', isLastBatch ? 'YES' : 'NO');

if (isLastBatch) {
  console.log('\n✓ ALL BATCHES COMPLETE!');
  console.log('   - Processed all', totalBatches, 'batches');
  console.log('   - Ready to mark task as complete');
  console.log('   - Moving to final summary...');
} else {
  console.log('\n↻ MORE BATCHES REMAINING');
  console.log('   - Next batch:', currentBatch + 1, 'of', totalBatches);
  console.log('   - Looping back to "Split Into Batches" node');
  console.log('   - The cycle continues...');
}
console.log('-'.repeat(80));

return items;

// STEP 8: Aggregate Results and Show Final Summary
// This runs ONCE after all batches are complete

const items = $input.all();
const taskId = items[0].json.taskId;
const totalUnits = items[0].json.totalUnits;
const totalBatches = items[0].json.totalBatches;

// Aggregate all results
const successCount = items.filter(i => i.json.processingResult === 'success').length;
const failedCount = items.filter(i => i.json.processingResult === 'failed').length;
const skippedCount = items.filter(i => i.json.processingResult === 'skipped').length;

// Calculate total processing time
const totalProcessingTime = items.reduce((sum, item) => sum + (item.json.processingTimeMs || 0), 0);

// Count lease extensions
const leaseExtensions = Math.max(...items.map(i => i.json.leaseExtensionCount || 0));

// Find any errors
const errors = items
  .filter(i => i.json.error)
  .map(i => ({
    customer: i.json.customer.name,
    error: i.json.error.message
  }));

console.log('\n');
console.log('='.repeat(80));
console.log('🎉 STEP 8: FINAL SUMMARY - TASK COMPLETE!');
console.log('='.repeat(80));
console.log('\n📊 OVERALL STATISTICS:');
console.log('-'.repeat(80));
console.log('Task ID:', taskId);
console.log('Total Customers Processed:', totalUnits);
console.log('Total Batches:', totalBatches);
console.log('Batch Size:', items[0].json.batchSize);
console.log('\n✓ Success:', successCount, `(${Math.round(successCount/totalUnits*100)}%)`);
console.log('✗ Failed:', failedCount, `(${Math.round(failedCount/totalUnits*100)}%)`);
console.log('⚠️  Skipped:', skippedCount, `(${Math.round(skippedCount/totalUnits*100)}%)`);
console.log('\n⏱️  PERFORMANCE:');
console.log('-'.repeat(80));
console.log('Total Processing Time:', totalProcessingTime, 'ms');
console.log('Average per Customer:', Math.round(totalProcessingTime / totalUnits), 'ms');
console.log('Lease Extensions:', leaseExtensions);

if (errors.length > 0) {
  console.log('\n⚠️  ERRORS ENCOUNTERED:');
  console.log('-'.repeat(80));
  errors.forEach((err, idx) => {
    console.log(`${idx + 1}. ${err.customer}: ${err.error}`);
  });
}

console.log('\n💡 KEY TAKEAWAYS:');
console.log('-'.repeat(80));
console.log('✓ Batching prevented memory overload');
console.log('✓ Failed items didn\'t stop the entire task');
console.log('✓ Lease was extended', leaseExtensions, 'time(s) to prevent timeout');
console.log('✓ Each batch was processed independently');
console.log('✓ Progress was tracked throughout');
console.log('✓ Dummy nodes showed additional processing steps in the loop');

console.log('\n🔄 WHAT HAPPENS NEXT IN PRODUCTION:');
console.log('-'.repeat(80));
console.log('1. Call complete_task() to mark task as done');
console.log('2. Return results to database');
console.log('3. Update metrics (tasks processed, success rate)');
console.log('4. Clear current task from worker state');
console.log('5. Loop back to poll for next task');

console.log('\n' + '='.repeat(80));
console.log('🎓 END OF BATCH PROCESSING DEMO');
console.log('='.repeat(80) + '\n');

return [{
  json: {
    taskId: taskId,
    summary: {
      totalUnits: totalUnits,
      totalBatches: totalBatches,
      successCount: successCount,
      failedCount: failedCount,
      skippedCount: skippedCount,
      totalProcessingTime: totalProcessingTime,
      leaseExtensions: leaseExtensions,
      errors: errors
    }
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
